bool StructTraits<::proxy_resolver::mojom::blink::ProxyServer::DataView, ::proxy_resolver::mojom::blink::ProxyServerPtr>::Read(
    ::proxy_resolver::mojom::blink::ProxyServer::DataView input, ::proxy_resolver::mojom::blink::ProxyServerPtr* output)
{
    bool success = true;
    ::proxy_resolver::mojom::blink::ProxyServerPtr result(::proxy_resolver::mojom::blink::ProxyServer::New());

    if (success && !input.ReadScheme(&result->scheme))
        success = false;
    if (success && !input.ReadHost(&result->host))
        success = false;
    if (success)
        result->port = input.port();
    *output = std::move(result);
    return success;
}
